def research_design_audit_gate(design):
    # D1: C-TOTALITY - validate top-level structure
    if not isinstance(design, dict):
        return {"may_proceed": False, "reason": "Design is not a dict"}

    audit_findings = design.get('audit_findings')
    if audit_findings is not None and not isinstance(audit_findings, list):
        return {"may_proceed": False, "reason": "audit_findings is not a list"}

    rq_candidates = design.get('rq_candidates')
    if not isinstance(rq_candidates, list):
        return {"may_proceed": False, "reason": "rq_candidates is not a list"}

    # D4: rq_candidates must be non-empty
    if len(rq_candidates) == 0:
        return {"may_proceed": False, "reason": "rq_candidates is empty"}

    # D2: Check all MAJOR findings are properly dispositioned
    if audit_findings is not None:
        for finding in audit_findings:
            # Skip non-dict findings (treat as invalid)
            if not isinstance(finding, dict):
                return {"may_proceed": False, "reason": "Non-dict finding found"}

            severity = finding.get('severity')
            if severity == 'MAJOR':
                # Must have 'disposition' key
                if 'disposition' not in finding:
                    return {"may_proceed": False, "reason": "MAJOR finding missing 'disposition' key"}

                disposition = finding.get('disposition')
                # Must be one of the valid dispositions (NOT 'OPEN')
                if disposition not in ('RESOLVED', 'REJECTED', 'MOVED_TO_GAP'):
                    return {"may_proceed": False, "reason": "MAJOR finding has invalid or 'OPEN' disposition"}

    # D3: If any finding has disposition 'RESOLVED', revision_ref must be non-empty
    if audit_findings is not None:
        has_resolved = any(
            isinstance(f, dict) and f.get('disposition') == 'RESOLVED'
            for f in audit_findings
        )
        if has_resolved:
            revision_ref = design.get('revision_ref')
            if not isinstance(revision_ref, str) or len(revision_ref) == 0:
                return {"may_proceed": False, "reason": "RESOLVED finding found but revision_ref missing or empty"}

    return {"may_proceed": True, "reason": "All checks passed"}
